import{_ as o,C as n,o as s,c as i,a3 as d,E as c,w as l,j as e,a}from"./chunks/framework.CCylkYel.js";const k=JSON.parse('{"title":"Macro rows on Perform","description":"","frontmatter":{},"headers":[],"relativePath":"perform/macro-rows/index.md","filePath":"perform/macro-rows/index.md"}'),m={name:"perform/macro-rows/index.md"};function h(p,r,u,f,g,w){const t=n("ManualRelated");return s(),i("div",null,[r[1]||(r[1]=d('<h1 id="macro-rows-on-perform" tabindex="-1">Macro rows on Perform <a class="header-anchor" href="#macro-rows-on-perform" aria-label="Permalink to &quot;Macro rows on Perform&quot;">​</a></h1><p>Each knob has <strong>four macro rows</strong> (numbered <strong>0–3</strong>) under the header. While you perform, each row tells you what that macro is doing right now — not a menu to edit, but a live status line tied to the knob position.</p><p>Turn the knob and every active row updates together. The <a href="./../knob-view#macro-indicator-bars">indicator bars</a> on the far right show the same levels graphically.</p><h2 id="the-basic-idea" tabindex="-1">The basic idea <a class="header-anchor" href="#the-basic-idea" aria-label="Permalink to &quot;The basic idea&quot;">​</a></h2><ul><li><strong>One row = one macro</strong> on this knob.</li><li><strong>What appears in the row depends on the macro mode</strong> — a CC row looks different from a device-parameter row or an LFO row.</li><li><strong>Empty macro</strong> — the row shows a centered <strong><code>-</code></strong> dash.</li><li><strong>Custom name</strong> — classic MIDI macros can carry a <a href="./classic-midi#name-a-control">control name</a> that replaces the message/parameter columns.</li><li><strong>Pickup armed</strong> — the value is <strong>dimmer</strong> and the <a href="./../knob-view#pickup-mode">indicator bar</a> shows a <strong>dotted line</strong> at the catch-up point. See <a href="./../knob-view#pickup-mode">Pickup mode</a>.</li></ul><table tabindex="0"><thead><tr><th>Guide</th><th>Use when the macro sends or drives…</th></tr></thead><tbody><tr><td><a href="./classic-midi">Classic MIDI</a></td><td>CC, 14-bit CC, program change, aftertouch, NRPN, RPN (<a href="./sysex">SysEx</a> — coming soon)</td></tr><tr><td><a href="./device-parameter">Device parameter</a></td><td>A parameter on a rack device (Arp, Harmony, Seed, Step Seq, …)</td></tr><tr><td><a href="./lfo-parameter">LFO parameter</a></td><td>An S32 or CV16 <strong>LFO parameter</strong> (rate, depth, phase, …)</td></tr><tr><td><a href="./cv16-control">CV16 control</a></td><td>A <strong>CV16 output jack</strong> (control voltage)</td></tr></tbody></table><p>To change what a row does, enter <a href="./../edit-mode">edit mode</a> and open that macro’s grid. Setup walkthrough: <a href="./../../macros/setting-up-macros">Setting up macros</a>.</p>',7)),c(t,null,{default:l(()=>[...r[0]||(r[0]=[e("ul",null,[e("li",null,[e("a",{href:"./../knob-view"},"Perform View"),a(" — Header, navigation, indicator bars, "),e("a",{href:"./../knob-view#pickup-mode"},"pickup mode")]),e("li",null,[e("a",{href:"./../edit-mode"},"Edit Mode"),a(" — Select and edit a macro row")]),e("li",null,[e("a",{href:"./../../macros/"},"Macro reference"),a(" — Full parameter grids per mode")])],-1)])]),_:1})])}const _=o(m,[["render",h]]);export{k as __pageData,_ as default};
